package com.videodownload.app.parser

/**
 * 视频解析器接口
 */
interface VideoParser {
    /**
     * 检查是否支持该 URL
     */
    fun supports(url: String): Boolean

    /**
     * 解析视频信息
     * @param url 视频 URL
     * @return 视频信息
     * @throws ParserException 解析失败时抛出
     */
    suspend fun parse(url: String): VideoInfo

    /**
     * 获取平台名称
     */
    fun getPlatform(): Platform
}

/**
 * 解析异常
 */
class ParserException(message: String, cause: Throwable? = null) : Exception(message, cause)

package com.videodownload.app.parser

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONObject
import java.net.URLDecoder
import java.util.concurrent.TimeUnit

/**
 * B站视频解析器
 * 支持 BV 号和 AV 号
 */
class BilibiliParser(
    private val client: OkHttpClient = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()
) : VideoParser {

    companion object {
        private const val TAG = "BilibiliParser"
        private const val USER_AGENT = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
        private const val REFERER = "https://www.bilibili.com"

        // API 端点
        private const val API_VIDEO_INFO = "https://api.bilibili.com/x/web-interface/view"
        private const val API_PLAYURL = "https://api.bilibili.com/x/player/playurl"
    }

    override fun supports(url: String): Boolean {
        return url.contains("bilibili.com") ||
               url.contains("b23.tv") ||
               url.matches(Regex("BV[a-zA-Z0-9]+")) ||
               url.matches(Regex("av\\d+"))
    }

    override suspend fun parse(url: String): VideoInfo = withContext(Dispatchers.IO) {
        try {
            // 提取视频 ID
            val videoId = extractVideoId(url)
            Log.d(TAG, "Parsing Bilibili video: $videoId")

            // 获取视频信息
            val videoInfo = fetchVideoInfo(videoId)

            // 获取播放地址
            val playUrl = fetchPlayUrl(videoId, videoInfo.getString("cid"))

            // 解析视频格式
            val formats = parseFormats(playUrl)
            val audioFormats = parseAudioFormats(playUrl)

            VideoInfo(
                id = videoId,
                title = videoInfo.getString("title"),
                description = videoInfo.optString("desc"),
                duration = videoInfo.getLong("duration"),
                thumbnailUrl = videoInfo.getString("pic"),
                author = videoInfo.getJSONObject("owner").getString("name"),
                platform = Platform.BILIBILI,
                formats = formats,
                audioFormats = audioFormats,
                uploadDate = formatTimestamp(videoInfo.getLong("pubdate")),
                viewCount = videoInfo.getJSONObject("stat").optLong("view")
            )
        } catch (e: Exception) {
            Log.e(TAG, "Failed to parse Bilibili video", e)
            throw ParserException("解析 B站 视频失败: ${e.message}", e)
        }
    }

    override fun getPlatform(): Platform = Platform.BILIBILI

    /**
     * 提取视频 ID (BV 号或 AV 号)
     */
    private fun extractVideoId(url: String): String {
        // 如果已经是 BV 或 AV 号，直接返回
        if (url.matches(Regex("BV[a-zA-Z0-9]+"))) {
            return url
        }
        if (url.matches(Regex("av\\d+"))) {
            return url
        }

        // 从 URL 中提取
        val bvMatch = Regex("BV[a-zA-Z0-9]+").find(url)
        if (bvMatch != null) {
            return bvMatch.value
        }

        val avMatch = Regex("av(\\d+)").find(url)
        if (avMatch != null) {
            return "av${avMatch.groupValues[1]}"
        }

        throw ParserException("无法从 URL 中提取视频 ID: $url")
    }

    /**
     * 获取视频信息
     */
    private fun fetchVideoInfo(videoId: String): JSONObject {
        val param = if (videoId.startsWith("BV")) "bvid" else "aid"
        val aid = if (videoId.startsWith("av")) videoId.substring(2) else videoId

        val url = "$API_VIDEO_INFO?$param=$aid"

        val request = Request.Builder()
            .url(url)
            .header("User-Agent", USER_AGENT)
            .header("Referer", REFERER)
            .build()

        client.newCall(request).execute().use { response ->
            if (!response.isSuccessful) {
                throw ParserException("获取视频信息失败: HTTP ${response.code}")
            }

            val json = JSONObject(response.body!!.string())
            if (json.getInt("code") != 0) {
                throw ParserException("API 返回错误: ${json.optString("message")}")
            }

            return json.getJSONObject("data")
        }
    }

    /**
     * 获取播放地址
     */
    private fun fetchPlayUrl(videoId: String, cid: String): JSONObject {
        val aid = if (videoId.startsWith("av")) videoId.substring(2) else videoId
        val param = if (videoId.startsWith("BV")) "bvid" else "avid"

        // qn: 视频质量 (80=1080P, 64=720P, 32=480P, 16=360P)
        // fnval: 返回格式 (16=DASH)
        val url = "$API_PLAYURL?$param=$aid&cid=$cid&qn=80&fnval=16&fourk=1"

        val request = Request.Builder()
            .url(url)
            .header("User-Agent", USER_AGENT)
            .header("Referer", REFERER)
            .build()

        client.newCall(request).execute().use { response ->
            if (!response.isSuccessful) {
                throw ParserException("获取播放地址失败: HTTP ${response.code}")
            }

            val json = JSONObject(response.body!!.string())
            if (json.getInt("code") != 0) {
                throw ParserException("API 返回错误: ${json.optString("message")}")
            }

            return json.getJSONObject("data")
        }
    }

    /**
     * 解析视频格式
     */
    private fun parseFormats(playUrl: JSONObject): List<VideoFormat> {
        val formats = mutableListOf<VideoFormat>()

        // DASH 格式
        if (playUrl.has("dash")) {
            val dash = playUrl.getJSONObject("dash")
            val videos = dash.getJSONArray("video")

            for (i in 0 until videos.length()) {
                val video = videos.getJSONObject(i)

                formats.add(
                    VideoFormat(
                        formatId = video.getInt("id").toString(),
                        url = video.getString("baseUrl"),
                        quality = getQualityName(video.getInt("id")),
                        width = video.optInt("width"),
                        height = video.optInt("height"),
                        fps = video.optInt("frameRate"),
                        fileSize = video.optLong("bandwidth") / 8, // 转换为字节
                        codec = video.optString("codecs"),
                        ext = "mp4",
                        isDash = true,
                        bitrate = video.optLong("bandwidth")
                    )
                )
            }
        }

        // FLV 格式（备用）
        if (playUrl.has("durl")) {
            val durls = playUrl.getJSONArray("durl")
            for (i in 0 until durls.length()) {
                val durl = durls.getJSONObject(i)

                formats.add(
                    VideoFormat(
                        formatId = "flv_$i",
                        url = durl.getString("url"),
                        quality = "标清",
                        width = null,
                        height = null,
                        fps = null,
                        fileSize = durl.optLong("size"),
                        codec = null,
                        ext = "flv",
                        isDash = false
                    )
                )
            }
        }

        return formats.sortedByDescending { it.height ?: 0 }
    }

    /**
     * 解析音频格式
     */
    private fun parseAudioFormats(playUrl: JSONObject): List<AudioFormat>? {
        if (!playUrl.has("dash")) return null

        val dash = playUrl.getJSONObject("dash")
        if (!dash.has("audio")) return null

        val audios = dash.getJSONArray("audio")
        val formats = mutableListOf<AudioFormat>()

        for (i in 0 until audios.length()) {
            val audio = audios.getJSONObject(i)

            formats.add(
                AudioFormat(
                    formatId = audio.getInt("id").toString(),
                    url = audio.getString("baseUrl"),
                    codec = audio.optString("codecs"),
                    bitrate = audio.optLong("bandwidth"),
                    fileSize = audio.optLong("bandwidth") / 8,
                    ext = "m4a"
                )
            )
        }

        return formats.sortedByDescending { it.bitrate ?: 0 }
    }

    /**
     * 获取画质名称
     */
    private fun getQualityName(qn: Int): String {
        return when (qn) {
            127 -> "8K"
            126 -> "杜比视界"
            125 -> "HDR"
            120 -> "4K"
            116 -> "1080P60"
            112 -> "1080P+"
            80 -> "1080P"
            74 -> "720P60"
            64 -> "720P"
            48 -> "720P"
            32 -> "480P"
            16 -> "360P"
            else -> "${qn}P"
        }
    }

    /**
     * 格式化时间戳
     */
    private fun formatTimestamp(timestamp: Long): String {
        val date = java.util.Date(timestamp * 1000)
        val format = java.text.SimpleDateFormat("yyyy-MM-dd", java.util.Locale.getDefault())
        return format.format(date)
    }
}

package com.videodownload.app.parser

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONObject
import java.net.URLDecoder
import java.util.concurrent.TimeUnit

/**
 * YouTube 视频解析器
 * 使用 YouTube 内部 API (innertube)
 */
class YouTubeParser(
    private val client: OkHttpClient = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()
) : VideoParser {

    companion object {
        private const val TAG = "YouTubeParser"
        private const val USER_AGENT = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"

        // YouTube API
        private const val API_KEY = "AIzaSyAO_FJ2SlqU8Q4STEHLGCilw_Y9_11qcW8"
        private const val API_ENDPOINT = "https://www.youtube.com/youtubei/v1/player"
        private const val CLIENT_VERSION = "2.20240101.00.00"
    }

    override fun supports(url: String): Boolean {
        return url.contains("youtube.com") ||
               url.contains("youtu.be") ||
               url.matches(Regex("[a-zA-Z0-9_-]{11}"))
    }

    override suspend fun parse(url: String): VideoInfo = withContext(Dispatchers.IO) {
        try {
            // 提取视频 ID
            val videoId = extractVideoId(url)
            Log.d(TAG, "Parsing YouTube video: $videoId")

            // 获取视频信息
            val playerResponse = fetchPlayerResponse(videoId)

            // 解析视频详情
            val videoDetails = playerResponse.getJSONObject("videoDetails")

            // 解析流媒体数据
            val streamingData = playerResponse.optJSONObject("streamingData")
                ?: throw ParserException("无法获取流媒体数据，视频可能受地区限制或需要登录")

            // 解析格式
            val formats = parseFormats(streamingData)
            val audioFormats = parseAudioFormats(streamingData)

            VideoInfo(
                id = videoId,
                title = videoDetails.getString("title"),
                description = videoDetails.optString("shortDescription"),
                duration = videoDetails.getLong("lengthSeconds"),
                thumbnailUrl = getBestThumbnail(videoDetails),
                author = videoDetails.getString("author"),
                platform = Platform.YOUTUBE,
                formats = formats,
                audioFormats = audioFormats,
                viewCount = videoDetails.optLong("viewCount")
            )
        } catch (e: Exception) {
            Log.e(TAG, "Failed to parse YouTube video", e)
            throw ParserException("解析 YouTube 视频失败: ${e.message}", e)
        }
    }

    override fun getPlatform(): Platform = Platform.YOUTUBE

    /**
     * 提取视频 ID
     */
    private fun extractVideoId(url: String): String {
        // 如果已经是视频 ID，直接返回
        if (url.matches(Regex("[a-zA-Z0-9_-]{11}"))) {
            return url
        }

        // youtu.be 短链接
        val shortMatch = Regex("youtu\\.be/([a-zA-Z0-9_-]{11})").find(url)
        if (shortMatch != null) {
            return shortMatch.groupValues[1]
        }

        // youtube.com 标准链接
        val standardMatch = Regex("[?&]v=([a-zA-Z0-9_-]{11})").find(url)
        if (standardMatch != null) {
            return standardMatch.groupValues[1]
        }

        // embed 链接
        val embedMatch = Regex("embed/([a-zA-Z0-9_-]{11})").find(url)
        if (embedMatch != null) {
            return embedMatch.groupValues[1]
        }

        throw ParserException("无法从 URL 中提取视频 ID: $url")
    }

    /**
     * 获取播放器响应
     */
    private fun fetchPlayerResponse(videoId: String): JSONObject {
        val requestBody = JSONObject().apply {
            put("videoId", videoId)
            put("context", JSONObject().apply {
                put("client", JSONObject().apply {
                    put("clientName", "WEB")
                    put("clientVersion", CLIENT_VERSION)
                    put("hl", "zh-CN")
                    put("gl", "CN")
                })
            })
        }

        val request = Request.Builder()
            .url("$API_ENDPOINT?key=$API_KEY")
            .post(
                okhttp3.RequestBody.create(
                    okhttp3.MediaType.parse("application/json"),
                    requestBody.toString()
                )
            )
            .header("User-Agent", USER_AGENT)
            .header("Content-Type", "application/json")
            .build()

        client.newCall(request).execute().use { response ->
            if (!response.isSuccessful) {
                throw ParserException("获取播放器响应失败: HTTP ${response.code}")
            }

            val json = JSONObject(response.body!!.string())

            // 检查是否有错误
            if (json.has("playabilityStatus")) {
                val status = json.getJSONObject("playabilityStatus")
                val statusValue = status.getString("status")

                if (statusValue != "OK") {
                    val reason = status.optString("reason", "未知错误")
                    throw ParserException("视频不可播放: $reason")
                }
            }

            return json
        }
    }

    /**
     * 解析视频格式
     */
    private fun parseFormats(streamingData: JSONObject): List<VideoFormat> {
        val formats = mutableListOf<VideoFormat>()

        // 解析 formats (包含音视频)
        if (streamingData.has("formats")) {
            val formatsArray = streamingData.getJSONArray("formats")
            for (i in 0 until formatsArray.length()) {
                val format = formatsArray.getJSONObject(i)
                parseFormat(format, false)?.let { formats.add(it) }
            }
        }

        // 解析 adaptiveFormats (仅视频，DASH)
        if (streamingData.has("adaptiveFormats")) {
            val adaptiveFormats = streamingData.getJSONArray("adaptiveFormats")
            for (i in 0 until adaptiveFormats.length()) {
                val format = adaptiveFormats.getJSONObject(i)

                // 只处理视频格式
                if (format.optString("mimeType").startsWith("video/")) {
                    parseFormat(format, true)?.let { formats.add(it) }
                }
            }
        }

        return formats.sortedByDescending { it.height ?: 0 }
    }

    /**
     * 解析单个格式
     */
    private fun parseFormat(format: JSONObject, isDash: Boolean): VideoFormat? {
        try {
            val url = format.optString("url") ?: format.optString("signatureCipher")?.let {
                // 处理签名加密的 URL（需要解密，这里简化处理）
                decodeSignatureCipher(it)
            } ?: return null

            val mimeType = format.getString("mimeType")
            val ext = extractExtension(mimeType)

            val width = format.optInt("width")
            val height = format.optInt("height")
            val quality = if (height > 0) "${height}p" else format.optString("qualityLabel", "未知")

            return VideoFormat(
                formatId = format.getString("itag"),
                url = url,
                quality = quality,
                width = width,
                height = height,
                fps = format.optInt("fps"),
                fileSize = format.optLong("contentLength"),
                codec = extractCodec(mimeType),
                ext = ext,
                isDash = isDash,
                bitrate = format.optLong("bitrate")
            )
        } catch (e: Exception) {
            Log.w(TAG, "Failed to parse format: ${e.message}")
            return null
        }
    }

    /**
     * 解析音频格式
     */
    private fun parseAudioFormats(streamingData: JSONObject): List<AudioFormat>? {
        if (!streamingData.has("adaptiveFormats")) return null

        val adaptiveFormats = streamingData.getJSONArray("adaptiveFormats")
        val formats = mutableListOf<AudioFormat>()

        for (i in 0 until adaptiveFormats.length()) {
            val format = adaptiveFormats.getJSONObject(i)

            // 只处理音频格式
            if (format.optString("mimeType").startsWith("audio/")) {
                try {
                    val url = format.optString("url") ?: format.optString("signatureCipher")?.let {
                        decodeSignatureCipher(it)
                    } ?: continue

                    val mimeType = format.getString("mimeType")
                    val ext = extractExtension(mimeType)

                    formats.add(
                        AudioFormat(
                            formatId = format.getString("itag"),
                            url = url,
                            codec = extractCodec(mimeType),
                            bitrate = format.optLong("bitrate"),
                            fileSize = format.optLong("contentLength"),
                            ext = ext
                        )
                    )
                } catch (e: Exception) {
                    Log.w(TAG, "Failed to parse audio format: ${e.message}")
                }
            }
        }

        return formats.sortedByDescending { it.bitrate ?: 0 }
    }

    /**
     * 解码签名加密的 URL
     */
    private fun decodeSignatureCipher(cipher: String): String {
        val params = cipher.split("&").associate {
            val parts = it.split("=", limit = 2)
            parts[0] to URLDecoder.decode(parts.getOrNull(1) ?: "", "UTF-8")
        }

        val url = params["url"] ?: throw ParserException("无法解析加密 URL")

        // 注意：完整的签名解密需要提取并执行 YouTube 的 JavaScript 代码
        // 这里简化处理，实际使用时可能需要更复杂的解密逻辑
        val signature = params["s"]
        val signatureParam = params["sp"] ?: "signature"

        return if (signature != null) {
            "$url&$signatureParam=$signature"
        } else {
            url
        }
    }

    /**
     * 从 MIME 类型提取扩展名
     */
    private fun extractExtension(mimeType: String): String {
        return when {
            mimeType.contains("mp4") -> "mp4"
            mimeType.contains("webm") -> "webm"
            mimeType.contains("3gpp") -> "3gp"
            mimeType.contains("m4a") -> "m4a"
            mimeType.contains("mp3") -> "mp3"
            else -> "mp4"
        }
    }

    /**
     * 从 MIME 类型提取编码器
     */
    private fun extractCodec(mimeType: String): String? {
        val codecMatch = Regex("codecs=\"([^\"]+)\"").find(mimeType)
        return codecMatch?.groupValues?.get(1)
    }

    /**
     * 获取最佳缩略图
     */
    private fun getBestThumbnail(videoDetails: JSONObject): String? {
        if (!videoDetails.has("thumbnail")) return null

        val thumbnail = videoDetails.getJSONObject("thumbnail")
        if (!thumbnail.has("thumbnails")) return null

        val thumbnails = thumbnail.getJSONArray("thumbnails")
        if (thumbnails.length() == 0) return null

        // 返回最后一个（通常是最高质量）
        return thumbnails.getJSONObject(thumbnails.length() - 1).getString("url")
    }
}

package com.videodownload.app.parser

/**
 * 视频解析器工厂
 * 根据 URL 自动选择合适的解析器
 */
object ParserFactory {

    private val parsers: List<VideoParser> = listOf(
        BilibiliParser(),
        YouTubeParser()
    )

    /**
     * 根据 URL 获取解析器
     * @param url 视频 URL
     * @return 支持该 URL 的解析器
     * @throws ParserException 如果没有找到支持的解析器
     */
    fun getParser(url: String): VideoParser {
        return parsers.firstOrNull { it.supports(url) }
            ?: throw ParserException("不支持的视频平台: $url")
    }

    /**
     * 检测 URL 的平台
     * @param url 视频 URL
     * @return 平台类型，如果无法识别则返回 UNKNOWN
     */
    fun detectPlatform(url: String): Platform {
        return parsers.firstOrNull { it.supports(url) }?.getPlatform() ?: Platform.UNKNOWN
    }

    /**
     * 解析视频信息
     * @param url 视频 URL
     * @return 视频信息
     * @throws ParserException 解析失败时抛出
     */
    suspend fun parse(url: String): VideoInfo {
        val parser = getParser(url)
        return parser.parse(url)
    }
}

package com.videodownload.app.service

import android.util.Log
import com.videodownload.app.parser.AudioFormat
import com.videodownload.app.parser.VideoFormat
import com.videodownload.app.utils.FFmpegHelper
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.io.FileOutputStream
import java.util.concurrent.TimeUnit

/**
 * 视频下载服务
 */
class VideoDownloadService(
    private val client: OkHttpClient = OkHttpClient.Builder()
        .connectTimeout(60, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .build(),
    private val ffmpegHelper: FFmpegHelper
) {

    companion object {
        private const val TAG = "VideoDownloadService"
        private const val BUFFER_SIZE = 8192
    }

    /**
     * 下载进度
     */
    data class DownloadProgress(
        val bytesDownloaded: Long,
        val totalBytes: Long,
        val percentage: Int,
        val speed: Long, // bytes per second
        val status: Status
    ) {
        enum class Status {
            DOWNLOADING,
            MERGING,
            COMPLETED,
            FAILED
        }
    }

    /**
     * 下载视频
     * @param format 视频格式
     * @param audioFormat 音频格式（DASH 格式需要）
     * @param outputFile 输出文件
     * @param headers 额外的 HTTP 头（如 Referer）
     * @return 下载进度流
     */
    fun downloadVideo(
        format: VideoFormat,
        audioFormat: AudioFormat?,
        outputFile: File,
        headers: Map<String, String> = emptyMap()
    ): Flow<DownloadProgress> = flow {
        try {
            if (format.isDash && audioFormat != null) {
                // DASH 格式：需要分别下载视频和音频，然后合并
                downloadDashVideo(format, audioFormat, outputFile, headers) { progress ->
                    emit(progress)
                }
            } else {
                // 普通格式：直接下载
                downloadFile(format.url, outputFile, headers) { progress ->
                    emit(progress)
                }
            }

            emit(
                DownloadProgress(
                    bytesDownloaded = outputFile.length(),
                    totalBytes = outputFile.length(),
                    percentage = 100,
                    speed = 0,
                    status = DownloadProgress.Status.COMPLETED
                )
            )
        } catch (e: Exception) {
            Log.e(TAG, "Download failed", e)
            emit(
                DownloadProgress(
                    bytesDownloaded = 0,
                    totalBytes = 0,
                    percentage = 0,
                    speed = 0,
                    status = DownloadProgress.Status.FAILED
                )
            )
            throw e
        }
    }

    /**
     * 下载 DASH 格式视频
     */
    private suspend fun downloadDashVideo(
        videoFormat: VideoFormat,
        audioFormat: AudioFormat,
        outputFile: File,
        headers: Map<String, String>,
        onProgress: suspend (DownloadProgress) -> Unit
    ) = withContext(Dispatchers.IO) {
        val tempDir = File(outputFile.parent, "temp_${System.currentTimeMillis()}")
        tempDir.mkdirs()

        try {
            val videoFile = File(tempDir, "video.${videoFormat.ext}")
            val audioFile = File(tempDir, "audio.${audioFormat.ext}")

            // 下载视频流
            Log.d(TAG, "Downloading video stream...")
            downloadFile(videoFormat.url, videoFile, headers) { progress ->
                onProgress(progress.copy(percentage = progress.percentage / 2))
            }

            // 下载音频流
            Log.d(TAG, "Downloading audio stream...")
            downloadFile(audioFormat.url, audioFile, headers) { progress ->
                onProgress(progress.copy(percentage = 50 + progress.percentage / 2))
            }

            // 合并视频和音频
            Log.d(TAG, "Merging video and audio...")
            onProgress(
                DownloadProgress(
                    bytesDownloaded = 0,
                    totalBytes = 0,
                    percentage = 95,
                    speed = 0,
                    status = DownloadProgress.Status.MERGING
                )
            )

            ffmpegHelper.mergeVideoAudio(videoFile, audioFile, outputFile)

            Log.d(TAG, "Download completed: ${outputFile.absolutePath}")
        } finally {
            // 清理临时文件
            tempDir.deleteRecursively()
        }
    }

    /**
     * 下载文件
     */
    private suspend fun downloadFile(
        url: String,
        outputFile: File,
        headers: Map<String, String>,
        onProgress: suspend (DownloadProgress) -> Unit
    ) = withContext(Dispatchers.IO) {
        val requestBuilder = Request.Builder().url(url)

        // 添加自定义头
        headers.forEach { (key, value) ->
            requestBuilder.header(key, value)
        }

        // B站需要 Referer 和 User-Agent
        if (url.contains("bilivideo.com")) {
            requestBuilder.header("Referer", "https://www.bilibili.com")
            requestBuilder.header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")
        }

        val request = requestBuilder.build()

        client.newCall(request).execute().use { response ->
            if (!response.isSuccessful) {
                throw Exception("Download failed: HTTP ${response.code}")
            }

            val totalBytes = response.body?.contentLength() ?: -1L
            var downloadedBytes = 0L
            var lastUpdateTime = System.currentTimeMillis()
            var lastDownloadedBytes = 0L

            response.body?.byteStream()?.use { input ->
                FileOutputStream(outputFile).use { output ->
                    val buffer = ByteArray(BUFFER_SIZE)
                    var bytesRead: Int

                    while (input.read(buffer).also { bytesRead = it } != -1) {
                        output.write(buffer, 0, bytesRead)
                        downloadedBytes += bytesRead

                        // 每 500ms 更新一次进度
                        val currentTime = System.currentTimeMillis()
                        if (currentTime - lastUpdateTime >= 500) {
                            val timeDiff = (currentTime - lastUpdateTime) / 1000.0
                            val bytesDiff = downloadedBytes - lastDownloadedBytes
                            val speed = (bytesDiff / timeDiff).toLong()

                            val percentage = if (totalBytes > 0) {
                                ((downloadedBytes * 100) / totalBytes).toInt()
                            } else {
                                0
                            }

                            onProgress(
                                DownloadProgress(
                                    bytesDownloaded = downloadedBytes,
                                    totalBytes = totalBytes,
                                    percentage = percentage,
                                    speed = speed,
                                    status = DownloadProgress.Status.DOWNLOADING
                                )
                            )

                            lastUpdateTime = currentTime
                            lastDownloadedBytes = downloadedBytes
                        }
                    }
                }
            }
        }
    }

    /**
     * 格式化文件大小
     */
    fun formatFileSize(bytes: Long): String {
        return when {
            bytes < 1024 -> "$bytes B"
            bytes < 1024 * 1024 -> String.format("%.2f KB", bytes / 1024.0)
            bytes < 1024 * 1024 * 1024 -> String.format("%.2f MB", bytes / (1024.0 * 1024))
            else -> String.format("%.2f GB", bytes / (1024.0 * 1024 * 1024))
        }
    }

    /**
     * 格式化速度
     */
    fun formatSpeed(bytesPerSecond: Long): String {
        return "${formatFileSize(bytesPerSecond)}/s"
    }
}

package com.videodownload.app.parser

import android.content.Context
import android.util.Log
import com.videodownload.app.service.VideoDownloadService
import com.videodownload.app.utils.FFmpegHelper
import kotlinx.coroutines.flow.collect
import java.io.File

/**
 * 视频解析和下载工具类
 * 提供简化的 API 用于解析和下载视频
 */
class VideoDownloadHelper(private val context: Context) {

    companion object {
        private const val TAG = "VideoDownloadHelper"
    }

    private val downloadService = VideoDownloadService(
        ffmpegHelper = FFmpegHelper(context)
    )

    /**
     * 解析视频信息
     * @param url 视频 URL
     * @return 视频信息
     */
    suspend fun parseVideo(url: String): VideoInfo {
        Log.d(TAG, "Parsing video: $url")
        return ParserFactory.parse(url)
    }

    /**
     * 获取推荐的视频格式
     * 优先选择 1080p，如果没有则选择最高画质
     */
    fun getRecommendedFormat(videoInfo: VideoInfo): VideoFormat? {
        val formats = videoInfo.formats

        // 优先选择 1080p
        val format1080p = formats.firstOrNull { it.quality.contains("1080") }
        if (format1080p != null) return format1080p

        // 选择最高画质
        return formats.maxByOrNull { it.height ?: 0 }
    }

    /**
     * 获取推荐的音频格式
     * 选择最高比特率的音频
     */
    fun getRecommendedAudioFormat(videoInfo: VideoInfo): AudioFormat? {
        return videoInfo.audioFormats?.maxByOrNull { it.bitrate ?: 0 }
    }

    /**
     * 下载视频
     * @param videoInfo 视频信息
     * @param format 视频格式
     * @param outputDir 输出目录
     * @param onProgress 进度回调
     * @return 下载的文件
     */
    suspend fun downloadVideo(
        videoInfo: VideoInfo,
        format: VideoFormat,
        outputDir: File,
        onProgress: (VideoDownloadService.DownloadProgress) -> Unit = {}
    ): File {
        // 创建输出目录
        if (!outputDir.exists()) {
            outputDir.mkdirs()
        }

        // 生成文件名
        val fileName = sanitizeFileName(videoInfo.title) + ".${format.ext}"
        val outputFile = File(outputDir, fileName)

        // 如果是 DASH 格式，需要音频
        val audioFormat = if (format.isDash) {
            getRecommendedAudioFormat(videoInfo)
                ?: throw Exception("DASH 格式需要音频流，但未找到音频格式")
        } else {
            null
        }

        // 准备下载头
        val headers = when (videoInfo.platform) {
            Platform.BILIBILI -> mapOf(
                "Referer" to "https://www.bilibili.com",
                "User-Agent" to "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
            )
            else -> emptyMap()
        }

        // 下载
        Log.d(TAG, "Downloading video to: ${outputFile.absolutePath}")
        downloadService.downloadVideo(format, audioFormat, outputFile, headers).collect { progress ->
            onProgress(progress)
        }

        return outputFile
    }

    /**
     * 下载视频（自动选择推荐格式）
     */
    suspend fun downloadVideo(
        url: String,
        outputDir: File,
        onProgress: (VideoDownloadService.DownloadProgress) -> Unit = {}
    ): File {
        val videoInfo = parseVideo(url)
        val format = getRecommendedFormat(videoInfo)
            ?: throw Exception("未找到可用的视频格式")

        return downloadVideo(videoInfo, format, outputDir, onProgress)
    }

    /**
     * 清理文件名，移除非法字符
     */
    private fun sanitizeFileName(fileName: String): String {
        return fileName
            .replace(Regex("[\\\\/:*?\"<>|]"), "_")
            .take(100) // 限制长度
    }

    /**
     * 格式化视频信息为可读字符串
     */
    fun formatVideoInfo(videoInfo: VideoInfo): String {
        return buildString {
            appendLine("标题: ${videoInfo.title}")
            appendLine("作者: ${videoInfo.author ?: "未知"}")
            appendLine("平台: ${videoInfo.platform}")
            appendLine("时长: ${formatDuration(videoInfo.duration)}")
            appendLine("观看次数: ${videoInfo.viewCount?.let { formatNumber(it) } ?: "未知"}")
            appendLine()
            appendLine("可用格式:")
            videoInfo.formats.forEach { format ->
                appendLine("  - ${format.quality} (${format.ext}) ${format.fileSize?.let { formatFileSize(it) } ?: ""}")
            }
            if (!videoInfo.audioFormats.isNullOrEmpty()) {
                appendLine()
                appendLine("音频格式:")
                videoInfo.audioFormats.forEach { format ->
                    appendLine("  - ${format.codec} (${format.ext}) ${format.bitrate?.let { "${it / 1000} kbps" } ?: ""}")
                }
            }
        }
    }

    /**
     * 格式化时长
     */
    private fun formatDuration(seconds: Long): String {
        val hours = seconds / 3600
        val minutes = (seconds % 3600) / 60
        val secs = seconds % 60

        return if (hours > 0) {
            String.format("%d:%02d:%02d", hours, minutes, secs)
        } else {
            String.format("%d:%02d", minutes, secs)
        }
    }

    /**
     * 格式化数字
     */
    private fun formatNumber(number: Long): String {
        return when {
            number >= 100_000_000 -> String.format("%.1f亿", number / 100_000_000.0)
            number >= 10_000 -> String.format("%.1f万", number / 10_000.0)
            else -> number.toString()
        }
    }

    /**
     * 格式化文件大小
     */
    private fun formatFileSize(bytes: Long): String {
        return when {
            bytes < 1024 -> "$bytes B"
            bytes < 1024 * 1024 -> String.format("%.2f KB", bytes / 1024.0)
            bytes < 1024 * 1024 * 1024 -> String.format("%.2f MB", bytes / (1024.0 * 1024))
            else -> String.format("%.2f GB", bytes / (1024.0 * 1024 * 1024))
        }
    }
}

