                        VideoDownloadService.DownloadProgress.Status.MERGING -> {
                            Log.d(TAG, "Merging video and audio...")
                        }
                        VideoDownloadService.DownloadProgress.Status.COMPLETED -> {
                            Log.d(TAG, "Download completed!")
                        }
                        VideoDownloadService.DownloadProgress.Status.FAILED -> {
                            Log.e(TAG, "Download failed")
                        }
