) {
    val uiState by viewModel.uiState.collectAsState()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("视频解析") }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // URL 输入框
            OutlinedTextField(
                value = uiState.url,
                onValueChange = { viewModel.updateUrl(it) },
                label = { Text("视频链接") },
                placeholder = { Text("输入 B站 或 YouTube 链接") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true
            )

            // 解析按钮
            Button(
                onClick = { viewModel.parseVideo() },
                modifier = Modifier.fillMaxWidth(),
                enabled = uiState.url.isNotBlank() && !uiState.isLoading
            ) {
                Text(if (uiState.isLoading) "解析中..." else "解析视频")
