            Text(
                text = videoInfo.title,
                style = MaterialTheme.typography.titleMedium
            )

            Text(
                text = "作者: ${videoInfo.author ?: "未知"}",
                style = MaterialTheme.typography.bodyMedium
            )

            Text(
                text = "平台: ${videoInfo.platform}",
                style = MaterialTheme.typography.bodyMedium
            )

            Text(
                text = "时长: ${formatDuration(videoInfo.duration)}",
                style = MaterialTheme.typography.bodyMedium
            )

