import com.videodownload.app.service.VideoDownloadService
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.io.File

/**
 * 视频解析 ViewModel
 */
class VideoParserViewModel(application: Application) : AndroidViewModel(application) {

    private val helper = VideoDownloadHelper(application)

    private val _uiState = MutableStateFlow(VideoParserUiState())
    val uiState: StateFlow<VideoParserUiState> = _uiState.asStateFlow()

    /**
     * 更新 URL
     */
    fun updateUrl(url: String) {
        _uiState.value = _uiState.value.copy(
            url = url,
            error = null
        )
    }

    /**
     * 解析视频
     */
    fun parseVideo() {
        val url = _uiState.value.url.trim()
        if (url.isBlank()) {
            _uiState.value = _uiState.value.copy(error = "请输入视频链接")
            return
        }

        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(
                isLoading = true,
                error = null,
                videoInfo = null,
                selectedFormat = null
            )

            try {
                val videoInfo = helper.parseVideo(url)

                // 自动选择推荐格式
                val recommendedFormat = helper.getRecommendedFormat(videoInfo)

                _uiState.value = _uiState.value.copy(
                    isLoading = false,
                    videoInfo = videoInfo,
                    selectedFormat = recommendedFormat
                )
            } catch (e: Exception) {
                _uiState.value = _uiState.value.copy(
                    isLoading = false,
                    error = "解析失败: ${e.message}"
                )
            }
        }
    }

    /**
     * 选择格式
     */
    fun selectFormat(format: VideoFormat) {
        _uiState.value = _uiState.value.copy(selectedFormat = format)
    }

    /**
     * 下载视频
     */
    fun downloadVideo() {
        val videoInfo = _uiState.value.videoInfo ?: return
        val format = _uiState.value.selectedFormat ?: return

        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(
                isDownloading = true,
                downloadProgress = 0,
                error = null
            )

            try {
                val outputDir = File(
                    getApplication<Application>().getExternalFilesDir(null),
                    "downloads"
                )

                helper.downloadVideo(
                    videoInfo = videoInfo,
                    format = format,
                    outputDir = outputDir,
                    onProgress = { progress ->
                        _uiState.value = _uiState.value.copy(
                            downloadProgress = progress.percentage
                        )
                    }
                )

                _uiState.value = _uiState.value.copy(
                    isDownloading = false,
                    downloadProgress = 100,
                    error = null
                )
            } catch (e: Exception) {
                _uiState.value = _uiState.value.copy(
                    isDownloading = false,
                    downloadProgress = 0,
                    error = "下载失败: ${e.message}"
                )
            }
        }
    }
}

/**
 * UI 状态
 */
data class VideoParserUiState(
    val url: String = "",
    val isLoading: Boolean = false,
    val videoInfo: VideoInfo? = null,
    val selectedFormat: VideoFormat? = null,
    val isDownloading: Boolean = false,
    val downloadProgress: Int = 0,
    val error: String? = null
)

# 视频解析模块 - 快速开始

## 1. 最简单的使用方式

```kotlin
// 在 Activity 或 Fragment 中
val helper = VideoDownloadHelper(context)

lifecycleScope.launch {
    try {
        // 解析视频
        val videoInfo = helper.parseVideo("https://www.bilibili.com/video/BV1xx411c7mD")

        // 打印视频信息
        Log.d(TAG, helper.formatVideoInfo(videoInfo))

        // 下载视频（自动选择推荐格式）
        val outputDir = File(getExternalFilesDir(null), "downloads")
        val file = helper.downloadVideo(
            url = "https://www.bilibili.com/video/BV1xx411c7mD",
            outputDir = outputDir,
            onProgress = { progress ->
                Log.d(TAG, "下载进度: ${progress.percentage}%")
            }
        )

        Log.d(TAG, "下载完成: ${file.absolutePath}")
    } catch (e: Exception) {
        Log.e(TAG, "错误: ${e.message}")
    }
}
```

